#!/bin/bash
# ============================================================================
# update-externals.sh — Clone, pull, and changelog external dependencies
# ============================================================================
#
# Usage:
#   ./external/scripts/update-externals.sh all          # Update everything
#   ./external/scripts/update-externals.sh hexcode       # Update one dependency
#   ./external/scripts/update-externals.sh --list        # List all tracked deps
#   ./external/scripts/update-externals.sh --status      # Show version status
#
# What it does on update:
#   1. Clone repo/ if missing, or git pull if it exists
#   2. Generate diff summary (commits + changed files)
#   3. Append summary to CHANGELOG.md
#   4. Update commit hash and date in META.md
#
# ============================================================================

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
EXTERNAL_DIR="$(cd "$SCRIPT_DIR/.." && pwd)"

# ── Registry ────────────────────────────────────────────────────────────────
# Format: "name|category|repo_url|branch"
# Add new dependencies here.

DEPS=(
    "hexcode|plugins|https://github.com/itsriprod/hexcode.git|main"
    "hyui|plugins|https://github.com/Elliesaur/HyUI.git|main"
    "mhud|plugins|https://github.com/Buuz135/MHUD.git|main"
    "partypro|plugins|https://github.com/Tsum0ri/PartyPro_Hytale.git|main"
    "the-armory|plugins|https://github.com/azurefoxx98/The-Armory-Mod.git|main"
    "loot4everyone|plugins|https://github.com/MimStar/Loot4Everyone-Hytale.git|main"
    "vuetale|libraries|https://github.com/KelpyCode/Vuetale.git|master"
    "modtale|libraries|https://github.com/Modtale/modtale.git|develop"
    "modifold|platforms|https://github.com/modifold-website|org"
    "hytalemodding-wiki|platforms|https://github.com/HytaleModding/wiki.git|main"
)

# ── Colors ──────────────────────────────────────────────────────────────────

RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[0;33m'
BLUE='\033[0;34m'
CYAN='\033[0;36m'
NC='\033[0m' # No Color
BOLD='\033[1m'

# ── Helpers ─────────────────────────────────────────────────────────────────

log_info()    { echo -e "${BLUE}[INFO]${NC} $1"; }
log_success() { echo -e "${GREEN}[OK]${NC} $1"; }
log_warn()    { echo -e "${YELLOW}[WARN]${NC} $1"; }
log_error()   { echo -e "${RED}[ERROR]${NC} $1"; }
log_header()  { echo -e "\n${BOLD}${CYAN}━━━ $1 ━━━${NC}"; }

get_dep_field() {
    local entry="$1"
    local field="$2"
    echo "$entry" | cut -d'|' -f"$field"
}

find_dep() {
    local name="$1"
    for dep in "${DEPS[@]}"; do
        local dep_name
        dep_name=$(get_dep_field "$dep" 1)
        if [[ "$dep_name" == "$name" ]]; then
            echo "$dep"
            return 0
        fi
    done
    return 1
}

# ── Core: Update a single dependency ────────────────────────────────────────

update_dep() {
    local entry="$1"
    local name category repo_url branch
    name=$(get_dep_field "$entry" 1)
    category=$(get_dep_field "$entry" 2)
    repo_url=$(get_dep_field "$entry" 3)
    branch=$(get_dep_field "$entry" 4)

    local dep_dir="$EXTERNAL_DIR/$category/$name"
    local repo_dir="$dep_dir/repo"
    local meta_file="$dep_dir/META.md"
    local changelog_file="$dep_dir/CHANGELOG.md"
    local today
    today=$(date +%Y-%m-%d)

    log_header "$name ($category)"

    # Skip org-type entries (like modifold which is a GitHub org, not a single repo)
    if [[ "$branch" == "org" ]]; then
        log_warn "Skipping $name — GitHub org, not a single repo. Update manually."
        return 0
    fi

    # Ensure directory exists
    mkdir -p "$dep_dir"

    # Ensure CHANGELOG.md exists
    if [[ ! -f "$changelog_file" ]]; then
        echo "# $name — Changelog" > "$changelog_file"
        echo "" >> "$changelog_file"
        echo "Auto-generated by \`update-externals.sh\`. Each entry records what changed between pulls." >> "$changelog_file"
    fi

    # ── Clone or Pull ───────────────────────────────────────────────────────

    if [[ ! -d "$repo_dir/.git" ]]; then
        log_info "Cloning $repo_url → repo/"
        if ! git clone --branch "$branch" "$repo_url" "$repo_dir" 2>&1; then
            # Some repos use 'master' instead of 'main'
            log_warn "Branch '$branch' failed, trying 'master'..."
            git clone --branch master "$repo_url" "$repo_dir" 2>&1 || {
                log_error "Failed to clone $name"
                return 1
            }
        fi

        local hash
        hash=$(cd "$repo_dir" && git rev-parse --short HEAD)
        local full_hash
        full_hash=$(cd "$repo_dir" && git rev-parse HEAD)
        local commit_count
        commit_count=$(cd "$repo_dir" && git rev-list --count HEAD)

        log_success "Cloned $name — $commit_count commits, HEAD at $hash"

        # Record initial clone in changelog
        {
            echo ""
            echo "## Initial Clone — $today"
            echo ""
            echo "- **Commit**: \`$full_hash\`"
            echo "- **Branch**: $branch"
            echo "- **Total commits**: $commit_count"
            echo ""
        } >> "$changelog_file"

        # Update META.md commit hash if the file exists
        if [[ -f "$meta_file" ]]; then
            update_meta_hash "$meta_file" "$full_hash" "$today"
        fi

    else
        log_info "Pulling latest for $name..."

        local old_hash
        old_hash=$(cd "$repo_dir" && git rev-parse HEAD)

        # Pull latest
        (cd "$repo_dir" && git fetch origin && git pull origin "$(git rev-parse --abbrev-ref HEAD)") 2>&1 || {
            log_error "Failed to pull $name"
            return 1
        }

        local new_hash
        new_hash=$(cd "$repo_dir" && git rev-parse HEAD)

        if [[ "$old_hash" == "$new_hash" ]]; then
            log_success "$name is up to date (${new_hash:0:7})"
            return 0
        fi

        # ── Generate Diff Summary ──────────────────────────────────────────

        local old_short="${old_hash:0:7}"
        local new_short="${new_hash:0:7}"
        local commit_log
        commit_log=$(cd "$repo_dir" && git log --oneline "$old_hash..$new_hash" 2>/dev/null || echo "(no commits)")
        local diff_stat
        diff_stat=$(cd "$repo_dir" && git diff --stat "$old_hash..$new_hash" 2>/dev/null || echo "(no diff)")
        local files_changed
        files_changed=$(cd "$repo_dir" && git diff --name-only "$old_hash..$new_hash" 2>/dev/null | wc -l)

        log_success "Updated $name: $old_short → $new_short ($files_changed files changed)"

        # ── Append to CHANGELOG.md ─────────────────────────────────────────

        {
            echo ""
            echo "## Update $today — \`$old_short\` → \`$new_short\`"
            echo ""
            echo "### Commits"
            echo ""
            echo '```'
            echo "$commit_log"
            echo '```'
            echo ""
            echo "### Changed Files ($files_changed)"
            echo ""
            echo '```'
            echo "$diff_stat"
            echo '```'
            echo ""
            echo "---"
        } >> "$changelog_file"

        # Update META.md
        if [[ -f "$meta_file" ]]; then
            update_meta_hash "$meta_file" "$new_hash" "$today"
        fi
    fi
}

# ── Update META.md commit hash and date ─────────────────────────────────────

update_meta_hash() {
    local meta_file="$1"
    local new_hash="$2"
    local today="$3"

    # Update "Current Version" or "Current Commit" line
    if grep -q "Current Version" "$meta_file"; then
        sed -i "s/| Current Version .*/| Current Version | \`${new_hash:0:10}\` |/" "$meta_file"
    fi

    # Update "Last Updated" line
    if grep -q "Last Updated" "$meta_file"; then
        sed -i "s/| Last Updated .*/| Last Updated | $today |/" "$meta_file"
    fi
}

# ── Commands ────────────────────────────────────────────────────────────────

cmd_list() {
    echo -e "${BOLD}Tracked Dependencies${NC}\n"
    printf "  %-20s %-12s %s\n" "NAME" "CATEGORY" "REPOSITORY"
    printf "  %-20s %-12s %s\n" "────" "────────" "──────────"
    for dep in "${DEPS[@]}"; do
        local name category repo_url
        name=$(get_dep_field "$dep" 1)
        category=$(get_dep_field "$dep" 2)
        repo_url=$(get_dep_field "$dep" 3)
        printf "  %-20s %-12s %s\n" "$name" "$category" "$repo_url"
    done
}

cmd_status() {
    echo -e "${BOLD}Dependency Status${NC}\n"
    printf "  %-20s %-12s %-12s %s\n" "NAME" "CATEGORY" "STATUS" "COMMIT"
    printf "  %-20s %-12s %-12s %s\n" "────" "────────" "──────" "──────"
    for dep in "${DEPS[@]}"; do
        local name category
        name=$(get_dep_field "$dep" 1)
        category=$(get_dep_field "$dep" 2)
        local repo_dir="$EXTERNAL_DIR/$category/$name/repo"

        if [[ -d "$repo_dir/.git" ]]; then
            local hash
            hash=$(cd "$repo_dir" && git rev-parse --short HEAD)
            printf "  %-20s %-12s ${GREEN}%-12s${NC} %s\n" "$name" "$category" "cloned" "$hash"
        else
            printf "  %-20s %-12s ${YELLOW}%-12s${NC} %s\n" "$name" "$category" "not cloned" "—"
        fi
    done
}

cmd_update() {
    local target="$1"

    if [[ "$target" == "all" ]]; then
        log_header "Updating ALL dependencies"
        local success=0
        local failed=0
        for dep in "${DEPS[@]}"; do
            if update_dep "$dep"; then
                ((success++))
            else
                ((failed++))
            fi
        done
        echo ""
        log_header "Summary"
        log_info "Updated: $success, Failed: $failed"
    else
        local dep
        if dep=$(find_dep "$target"); then
            update_dep "$dep"
        else
            log_error "Unknown dependency: $target"
            echo "Run with --list to see all tracked dependencies."
            exit 1
        fi
    fi
}

# ── Main ────────────────────────────────────────────────────────────────────

if [[ $# -lt 1 ]]; then
    echo "Usage: $0 <name|all|--list|--status>"
    echo ""
    echo "Commands:"
    echo "  all        Update all dependencies"
    echo "  <name>     Update a single dependency"
    echo "  --list     List all tracked dependencies"
    echo "  --status   Show clone status and current commits"
    exit 0
fi

case "$1" in
    --list)   cmd_list ;;
    --status) cmd_status ;;
    *)        cmd_update "$1" ;;
esac
